#include <stdio.h>
#include <stdlib.h>

int height(int node, int left[], int right[]) {
    if (node == 0) return -1; // null contributes -1 so leaf becomes 0
    int lh = height(left[node], left, right);
    int rh = height(right[node], left, right);
    return (lh > rh ? lh : rh) + 1;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *left = (int*)calloc(N + 1, sizeof(int));
        int *right = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char r; scanf("%d %d %c", &p, &c, &r);
            if (r == 'L') left[p] = c; else right[p] = c;
        }
        int ans = height(1, left, right);
        printf("%d\n", ans);
        free(left);
        free(right);
    }
    return 0;
}

