#include <bits/stdc++.h>
using namespace std;

int height(int node, const vector<int>& left, const vector<int>& right) {
    if (node == 0) return -1;
    int lh = height(left[node], left, right);
    int rh = height(right[node], left, right);
    return max(lh, rh) + 1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> left(N + 1, 0), right(N + 1, 0);
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char r; cin >> p >> c >> r;
            if (r == 'L') left[p] = c; else right[p] = c;
        }
        cout << height(1, left, right) << '\n';
    }
    return 0;
}

